class UserService {
  static async create(userData) {
    const { name, email, role } = userData;
    
    if (!name || !email) {
      throw new Error('Name and email are required');
    }

    if (!InputValidator.validateEmail(email)) {
      throw new Error('Invalid email format');
    }

    const sanitizedName = InputValidator.sanitizeString(name, 100);
    const sanitizedEmail = InputValidator.sanitizeString(email, 255);
    const sanitizedRole = InputValidator.sanitizeString(role || 'user', 50);

    const query = `
      INSERT INTO users (name, email, role, created_at)
      VALUES ($1, $2, $3, NOW())
      RETURNING id, name, email, role, created_at
    `;

    try {
      const result = await pool.query(query, [sanitizedName, sanitizedEmail, sanitizedRole]);
      return result.rows[0];
    } catch (error) {
      if (error.code === '23505') {
        throw new Error('Email already exists');
      }
      throw error;
    }
  }

  static async getById(id) {
    const validId = InputValidator.validateId(id);
    if (!validId) {
      throw new Error('Invalid user ID');
    }

    const query = 'SELECT id, name, email, role, created_at FROM users WHERE id = $1';
    const result = await pool.query(query, [validId]);
    
    if (result.rows.length === 0) {
      return null;
    }
    
    return result.rows[0];
  }

  static async getAll(limit = 100, offset = 0) {
    const validLimit = Math.min(Math.max(parseInt(limit, 10) || 100, 1), 1000);
    const validOffset = Math.max(parseInt(offset, 10) || 0, 0);

    const query = `
      SELECT id, name, email, role, created_at 
      FROM users 
      ORDER BY created_at DESC 
      LIMIT $1 OFFSET $2
    `;
    
    const result = await pool.query(query, [validLimit, validOffset]);
    return result.rows;
  }

  static async update(id, userData) {
    const validId = InputValidator.validateId(id);
    if (!validId) {
      throw new Error('Invalid user ID');
    }

    const { name, email, role } = userData;
    const updates = [];
    const values = [];
    let paramCount = 1;

    if (name !== undefined) {
      updates.push(`name = $${paramCount++}`);
      values.push(InputValidator.sanitizeString(name, 100));
    }

    if (email !== undefined) {
      if (!InputValidator.validateEmail(email)) {
        throw new Error('Invalid email format');
      }
      updates.push(`email = $${paramCount++}`);
      values.push(InputValidator.sanitizeString(email, 255));
    }

    if (role !== undefined) {
      updates.push(`role = $${paramCount++}`);
      values.push(InputValidator.sanitizeString(role, 50));
    }

    if (updates.length === 0) {
      throw new Error('No valid fields to update');
    }

    values.push(validId);
    const query = `
      UPDATE users 
      SET ${updates.join(', ')}, updated_at = NOW()
      WHERE id = $${paramCount}
      RETURNING id, name, email, role, created_at, updated_at
    `;

    const result = await pool.query(query, values);
    
    if (result.rows.length === 0) {
      return null;
    }
    
    return result.rows[0];
  }

  static async delete(id) {
    const validId = InputValidator.validateId(id);
    if (!validId) {
      throw new Error('Invalid user ID');
    }

    const query = 'DELETE FROM users WHERE id = $1 RETURNING id';
    const result = await pool.query(query, [validId]);
    
    return result.rows.length > 0;
  }
}

