// Orders CRUD operations
class OrderService {
  static async create(orderData) {
    const { user_id, product_id, quantity, total_amount } = orderData;
    
    if (!user_id || !product_id || !quantity || !total_amount) {
      throw new Error('All fields are required');
    }

    const validUserId = InputValidator.validateId(user_id);
    const validProductId = InputValidator.validateId(product_id);
    const validQuantity = parseInt(quantity, 10);
    const validAmount = parseFloat(total_amount);

    if (!validUserId || !validProductId) {
      throw new Error('Invalid user or product ID');
    }

    if (isNaN(validQuantity) || validQuantity <= 0) {
      throw new Error('Invalid quantity');
    }

    if (isNaN(validAmount) || validAmount < 0) {
      throw new Error('Invalid total amount');
    }

    const client = await pool.connect();
    
    try {
      await client.query('BEGIN');

      const productCheck = await client.query(
        'SELECT stock FROM products WHERE id = $1 FOR UPDATE',
        [validProductId]
      );

      if (productCheck.rows.length === 0) {
        throw new Error('Product not found');
      }

      if (productCheck.rows[0].stock < validQuantity) {
        throw new Error('Insufficient stock');
      }

      const orderQuery = `
        INSERT INTO orders (user_id, product_id, quantity, total_amount, status, created_at)
        VALUES ($1, $2, $3, $4, 'pending', NOW())
        RETURNING id, user_id, product_id, quantity, total_amount, status, created_at
      `;

      const orderResult = await client.query(orderQuery, [
        validUserId,
        validProductId,
        validQuantity,
        validAmount
      ]);

      await client.query(
        'UPDATE products SET stock = stock - $1 WHERE id = $2',
        [validQuantity, validProductId]
      );

      await client.query('COMMIT');
      return orderResult.rows[0];
    } catch (error) {
      await client.query('ROLLBACK');
      throw error;
    } finally {
      client.release();
    }
  }

  static async getById(id) {
    const validId = InputValidator.validateId(id);
    if (!validId) {
      throw new Error('Invalid order ID');
    }

    const query = `
      SELECT o.id, o.user_id, o.product_id, o.quantity, o.total_amount, o.status, o.created_at,
             u.name as user_name, p.name as product_name
      FROM orders o
      JOIN users u ON o.user_id = u.id
      JOIN products p ON o.product_id = p.id
      WHERE o.id = $1
    `;
    
    const result = await pool.query(query, [validId]);
    
    if (result.rows.length === 0) {
      return null;
    }
    
    return result.rows[0];
  }

  static async getAll(limit = 100, offset = 0) {
    const validLimit = Math.min(Math.max(parseInt(limit, 10) || 100, 1), 1000);
    const validOffset = Math.max(parseInt(offset, 10) || 0, 0);

    const query = `
      SELECT o.id, o.user_id, o.product_id, o.quantity, o.total_amount, o.status, o.created_at,
             u.name as user_name, p.name as product_name
      FROM orders o
      JOIN users u ON o.user_id = u.id
      JOIN products p ON o.product_id = p.id
      ORDER BY o.created_at DESC 
      LIMIT $1 OFFSET $2
    `;
    
    const result = await pool.query(query, [validLimit, validOffset]);
    return result.rows;
  }

  static async updateStatus(id, status) {
    const validId = InputValidator.validateId(id);
    if (!validId) {
      throw new Error('Invalid order ID');
    }

    const allowedStatuses = ['pending', 'processing', 'completed', 'cancelled'];
    const sanitizedStatus = InputValidator.sanitizeString(status, 50).toLowerCase();

    if (!allowedStatuses.includes(sanitizedStatus)) {
      throw new Error('Invalid status');
    }

    const query = `
      UPDATE orders 
      SET status = $1, updated_at = NOW()
      WHERE id = $2
      RETURNING id, user_id, product_id, quantity, total_amount, status, created_at, updated_at
    `;

    const result = await pool.query(query, [sanitizedStatus, validId]);
    
    if (result.rows.length === 0) {
      return null;
    }
    
    return result.rows[0];
  }

  static async delete(id) {
    const validId = InputValidator.validateId(id);
    if (!validId) {
      throw new Error('Invalid order ID');
    }

    const query = 'DELETE FROM orders WHERE id = $1 RETURNING id';
    const result = await pool.query(query, [validId]);
    
    return result.rows.length > 0;
  }
}

// Database initialization with proper schema
async function initializeDatabase() {
  const client = await pool.connect();
  
  try {
    await client.query(`
      CREATE TABLE IF NOT EXISTS users (
        id SERIAL PRIMARY KEY,
        name VARCHAR(100) NOT NULL,
        email VARCHAR(255) UNIQUE NOT NULL,
        role VARCHAR(50) DEFAULT 'user',
        created_at TIMESTAMP DEFAULT NOW(),
        updated_at TIMESTAMP DEFAULT NOW()
      )
    `);

    await client.query(`
      CREATE TABLE IF NOT EXISTS products (
        id SERIAL PRIMARY KEY,
        name VARCHAR(200) NOT NULL,
        description TEXT,
        price DECIMAL(10, 2) NOT NULL CHECK (price >= 0),
        stock INTEGER DEFAULT 0 CHECK (stock >= 0),
        created_at TIMESTAMP DEFAULT NOW(),
        updated_at TIMESTAMP DEFAULT NOW()
      )
    `);

    await client.query(`
      CREATE TABLE IF NOT EXISTS orders (
        id SERIAL PRIMARY KEY,
        user_id INTEGER NOT NULL REFERENCES users(id) ON DELETE CASCADE,
        product_id INTEGER NOT NULL REFERENCES products(id) ON DELETE CASCADE,
        quantity INTEGER NOT NULL CHECK (quantity > 0),
        total_amount DECIMAL(10, 2) NOT NULL CHECK (total_amount >= 0),
        status VARCHAR(50) DEFAULT 'pending',
        created_at TIMESTAMP DEFAULT NOW(),
        updated_at TIMESTAMP DEFAULT NOW()
      )
    `);

    await client.query('CREATE INDEX IF NOT EXISTS idx_orders_user_id ON orders(user_id)');
    await client.query('CREATE INDEX IF NOT EXISTS idx_orders_product_id ON orders(product_id)');
    await client.query('CREATE INDEX IF NOT EXISTS idx_orders_status ON orders(status)');

    console.log('Database initialized successfully');
  } catch (error) {
    console.error('Database initialization error:', error);
    throw error;
  } finally {
    client.release();
  }
}

// Graceful shutdown
async function shutdown() {
  await pool.end();
  console.log('Database pool closed');
}

process.on('SIGTERM', shutdown);
process.on('SIGINT', shutdown);

module.exports = {
  pool,
  UserService,
  ProductService,
  OrderService,
  initializeDatabase,
  shutdown
};